// Subsetted Liberation Sans (ASCII 0x20-0x7E + U+20A6 Naira sign), generated via fonttools pyftsubset.
// jsPDF's standard fonts use WinAnsiEncoding and cannot render the Naira sign (₦), so this
// minimal embedded font is required for correct ₦ rendering in generated receipts.
export const NAIRA_FONT_REGULAR_B64 = "";
export const NAIRA_FONT_BOLD_B64 = "";
